    #[test]
    fn orchestration_mode_adds_polyglot_bridge_labels() {
        let mut cfg = ControlFlowGraph::new(
            "handler".to_string(),
            "python".to_string(),
            "app.py".to_string(),
        );
        let entry = cfg.add_node(
            CfgNodeKind::Entry {
                name: "handler".to_string(),
            },
            span(),
            "entry".to_string(),
        );
        cfg.entry = entry;
        let stmt = cfg.add_node(
            CfgNodeKind::Statement,
            span(),
            "call: fetch_data()".to_string(),
        );
        let ret = cfg.add_node(CfgNodeKind::Return, span(), "return".to_string());
        cfg.exits.push(ret);

        cfg.add_edge(entry, stmt, None);
        cfg.add_edge(stmt, ret, None);

        let gg = compile_cfg_to_gg_with_mode(&cfg, &CompilationMode::Orchestration);

        // Entry should have dual labels.
        let entry_node = gg
            .nodes
            .iter()
            .find(|n| n.labels.contains(&"Entry".to_string()))
            .expect("should have Entry node");
        assert!(
            entry_node
                .labels
                .contains(&"PolyglotBridgeEntry".to_string()),
            "Entry node should have PolyglotBridgeEntry label"
        );

        // Statement with call should be upgraded to PolyglotBridgeCall.
        let call_node = gg
            .nodes
            .iter()
            .find(|n| n.labels.contains(&"Statement".to_string()))
            .expect("should have Statement node");
        assert!(
            call_node.labels.contains(&"PolyglotBridgeCall".to_string()),
            "Statement with call should have PolyglotBridgeCall label"
        );
        assert!(
            call_node.properties.contains_key("callee"),
            "Call node should have callee property"
        );
        assert_eq!(
            call_node.properties.get("callee").unwrap(),
            "fetch_data",
            "Callee should be 'fetch_data'"
        );

        // Return should have dual labels.
        let ret_node = gg
            .nodes
            .iter()
            .find(|n| n.labels.contains(&"Return".to_string()))
            .expect("should have Return node");
        assert!(
            ret_node
                .labels
                .contains(&"PolyglotBridgeReturn".to_string()),
            "Return node should have PolyglotBridgeReturn label"
        );

        // All nodes should have source_start_byte and source_end_byte in orchestration mode.
        for node in &gg.nodes {
            assert!(
                node.properties.contains_key("source_start_byte"),
                "Node {} should have source_start_byte",
                node.id
            );
            assert!(
                node.properties.contains_key("source_end_byte"),
                "Node {} should have source_end_byte",
                node.id
            );
        }
    }

    #[test]
    fn orchestration_mode_lowers_promise_all_to_foil_fork_fold_sidecar() {
        let mut cfg = ControlFlowGraph::new(
            "app".to_string(),
            "typescript".to_string(),
            "fanout.ts".to_string(),
        );
        let entry = cfg.add_node(
            CfgNodeKind::Entry {
                name: "app".to_string(),
            },
            span(),
            "entry".to_string(),
        );
        cfg.entry = entry;
        let promise = cfg.add_node(
            CfgNodeKind::Statement,
            span(),
            "const [user, profile] = await Promise.all([loadUser(input.userId), loadProfile(input.userId)])".to_string(),
        );
        cfg.nodes[promise]
            .extra_properties
            .insert("callee".to_string(), "Promise.all".to_string());
        cfg.nodes[promise].extra_properties.insert(
            "bind_pattern".to_string(),
            r#"{"kind":"array_pattern","elements":[{"name":"user"},{"name":"profile"}]}"#
                .to_string(),
        );
        cfg.nodes[promise].extra_properties.insert(
            "args".to_string(),
            r#"[{"kind":"array","items":[{"kind":"call","callee":"loadUser","args":[{"kind":"member","obj":{"kind":"ident","name":"input"},"prop":"userId"}]},{"kind":"call","callee":"loadProfile","args":[{"kind":"member","obj":{"kind":"ident","name":"input"},"prop":"userId"}]}]}]"#
                .to_string(),
        );
        let merge = cfg.add_node(
            CfgNodeKind::Statement,
            span(),
            "merge(user, profile)".to_string(),
        );
        let ret = cfg.add_node(CfgNodeKind::Return, span(), "return".to_string());
        cfg.exits.push(ret);

        cfg.add_edge(entry, promise, None);
        cfg.add_edge(promise, merge, None);
        cfg.add_edge(merge, ret, None);

        let gg = compile_cfg_to_gg_with_mode(&cfg, &CompilationMode::Orchestration);

        let foil_fork = gg
            .edges
            .iter()
            .find(|edge| {
                edge.edge_type == GgEdgeType::Fork
                    && edge
                        .properties
                        .get("foil_lowering")
                        .is_some_and(|lowering| lowering == "Promise.all")
            })
            .expect("Promise.all should emit a foil FORK edge");
        assert_eq!(foil_fork.target_ids.len(), 2);

        let foil_fold = gg
            .edges
            .iter()
            .find(|edge| {
                edge.edge_type == GgEdgeType::Fold
                    && edge
                        .properties
                        .get("foil_lowering")
                        .is_some_and(|lowering| lowering == "Promise.all")
            })
            .expect("Promise.all should emit a foil FOLD edge");
        assert_eq!(foil_fold.source_ids.len(), 2);

        let branch_callees: Vec<_> = gg
            .nodes
            .iter()
            .filter(|node| node.labels.contains(&"FoilBranch".to_string()))
            .filter_map(|node| node.properties.get("callee").map(String::as_str))
            .collect();
        assert!(branch_callees.contains(&"loadUser"));
        assert!(branch_callees.contains(&"loadProfile"));
    }

